+
+const oneOf = <T extends string>(value: unknown, values: readonly T[], fallback: T): T =>
+  typeof value === 'string' && (values as readonly string[]).includes(value)
+    ? value as T
+    : fallback;
+
+/** Normalizes the public error-stack configuration exactly once per instance. */
+export function normalizeErrorStackOptions(
+  input: unknown
+): NormalizedErrorStackOptions | undefined {
+  if (typeof input !== 'object' || input === null) return undefined;
+
+  const value = input as ErrorStackOptions;
+  const mode = oneOf(value.mode, ['off', 'string', 'frames'] as const, 'off');
+  const maxStackLines = value.maxStackLines;
+  const invalidMaxStackLines =
+    maxStackLines !== undefined &&
+    (!Number.isInteger(maxStackLines) || maxStackLines <= 0);
+  const maxCauseDepth = value.maxCauseDepth;
+  const invalidMaxCauseDepth =
+    maxCauseDepth !== undefined && !Number.isInteger(maxCauseDepth);
+  const classFilter = Array.isArray(value.classFilter)
+    ? value.classFilter.filter((name): name is string => typeof name === 'string')
+    : undefined;
+
+  return {
+    mode: invalidMaxStackLines ? 'off' : mode,
+    normalizeNewlines: value.normalizeNewlines === true,
+    trimLeadingWhitespace: value.trimLeadingWhitespace !== false,
+    maxStackLines,
+    stripInternalFrames: oneOf(
+      value.stripInternalFrames,
+      ['none', 'node', 'superjson', 'node_and_superjson'] as const,
+      'none'
+    ),
+    redactPaths: oneOf(
+      value.redactPaths,
+      ['none', 'basename', 'strip_cwd'] as const,
+      'none'
+    ),
+    includeCauses: invalidMaxCauseDepth
+      ? 'none'
+      : oneOf(value.includeCauses, ['none', 'direct', 'deep'] as const, 'none'),
+    maxCauseDepth: maxCauseDepth === undefined ? 16 : maxCauseDepth,
+    sanitizeMessage: value.sanitizeMessage === true,
