+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
|\\r/g, '\
');
+}
+
+const shouldStrip = (line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) =>
+  (mode === 'node' || mode === 'node_and_superjson') && line.includes('node:internal') ||
+  (mode === 'superjson' || mode === 'node_and_superjson') &&
+    (line.includes('src/transformer.ts') || line.includes('src/plainer.ts') || line.includes('src/index.ts'));
+
+const redact = (line: string, options: NormalizedErrorStackOptions): string => {
+  if (options.redactPaths === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/').replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&');
+    return line.replace(new RegExp(cwd.replace(/\\//g, '[\\\\\\\\/]') + '[\\\\\\\\/]*', 'g'), '');
+  }
+  if (options.redactPaths === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?(?:[/\\\\][^\\s():/\\\\]+)+/g, path =>
+      path.split(/[/\\\\]/).pop()!
+    );
+  }
+  return line;
+};
+
+const split = (stack: string, options: NormalizedErrorStackOptions): string[] => {
+  let value = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let lines = value.split('\
');
+  if (options.trimLeadingWhitespace) {
+    lines = lines.map((line, index) => index === 0 ? line : line.replace(/^\\s+/, ''));
+  }
+  return lines;
+};
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  let lines = split(stack, options).map(line => redact(line, options));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  const [header, ...frames] = lines;
+  return [header, ...frames.filter(line => !shouldStrip(line, options.stripInternalFrames))].join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  let lines = split(stack, options);
+  const [header, ...frames] = lines;
+  lines = [header, ...frames.filter(line => !shouldStrip(line, options.stripInternalFrames))]
+    .map(line => redact(line, options));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  return lines.map(raw => ({ raw }));
+}
