+const isAggregateError = (value: Error): value is AggregateError =>
+  typeof AggregateError !== 'undefined' && value instanceof AggregateError;
+
+const isStackProcessedError = (
+  value: Error,
+  superJson: SuperJSON,
+  mode: 'string' | 'frames'
+): boolean => {
+  const options = superJson.errorStackOptions;
+  return !!options &&
+    options.mode === mode &&
+    (!options.classFilter || options.classFilter.includes(value.name));
+};
+
+const applyErrorProcessor = (error: any, superJson: SuperJSON): any => {
+  const processor = superJson.errorClassRegistry.getProcessor(error.name);
+  return processor ? processor(error) : error;
+};
+
+function serializeError(value: Error, superJson: SuperJSON): any {
+  const baseError: any = { name: value.name, message: value.message };
+
+  if ('cause' in value) baseError.cause = (value as any).cause;
+  if (isAggregateError(value)) baseError.errors = value.errors;
+
+  superJson.allowedErrorProps.forEach(prop => {
+    // A provided stack option owns these fields, including when it is off.
+    if (superJson.errorStackOptions && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (value as any)[prop];
+  });
+
+  return applyErrorProcessor(baseError, superJson);
+}
+
+function serializeProcessedError(
+  value: Error,
+  superJson: SuperJSON,
+  mode: 'string' | 'frames'
+): any {
+  const options = superJson.errorStackOptions!;
+  const baseError: any = {
+    name: value.name,
+    message: options.sanitizeMessage ? sanitizeMessage(value.message) : value.message,
+  };
+
+  if (isAggregateError(value)) baseError.errors = value.errors;
+
+  const depth = superJson.getErrorCauseDepth(value);
+  if (
+    options.includeCauses !== 'none' &&
+    depth > 0 &&
+    (value as any).cause instanceof Error
+  ) {
+    const cause = (value as any).cause as Error;
+    baseError.cause = cause;
+    superJson.setErrorCauseDepth(cause, depth - 1);
+  }
+
+  if (mode === 'string' && superJson.allowedErrorProps.includes('stack') && typeof value.stack === 'string') {
+    baseError.stack = processStackString(value.stack, options);
+  }
+  if (mode === 'frames' && superJson.allowedErrorProps.includes('stackFrames') && typeof value.stack === 'string') {
+    baseError.stackFrames = processStackFrames(value.stack, options);
+  }
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (prop !== 'stack' && prop !== 'stackFrames') baseError[prop] = (value as any)[prop];
+  });
+
+  return applyErrorProcessor(baseError, superJson);
+}
+
+function deserializeError(value: any, superJson: SuperJSON): Error {
+  const cause = value.cause;
+  const error = isAggregateError(value as Error)
+    ? new AggregateError(value.errors, value.message, { cause })
+    : new Error(value.message, { cause });
+  error.name = value.name;
+  if ('stack' in value) error.stack = value.stack;
+  if ('stackFrames' in value) (error as any).stackFrames = value.stackFrames;
+  if (isAggregateError(error) && 'errors' in value) (error as any).errors = value.errors;
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (prop !== 'stack' && prop !== 'stackFrames') (error as any)[prop] = value[prop];
+  });
+  return error;
+}

